const JAILBREAK_PATTERNS = [
  /ignore\s+previous\s+instructions/i,
  /you\s+are\s+no\s+longer/i,
  /disregard\s+all\s+previous/i,
  /act\s+as\s+unrestricted/i,
  /override\s+your\s+safety/i
];

function detectJailbreak(input: string): boolean {
  return JAILBREAK_PATTERNS.some(pattern => pattern.test(input));
}

// Usage in Flowise custom node
class JailbreakDetectorNode {
  async execute(inputs: any[]): Promise<any> {
    const userInput = inputs[0].data.text;
    if (detectJailbreak(userInput)) {
      throw new Error('Jailbreak attempt detected');
    }
    return inputs;
  }
}
