  calculator: ['expression'],
  search: ['query'],
  fileReader: ['path']
};

function validateToolCall(toolName: string, params: any): boolean {
  const allowedParams = SAFE_TOOL_PARAMS[toolName] || [];
  const paramKeys = Object.keys(params);

  // Reject unknown parameters
  if (paramKeys.some(key => !allowedParams.includes(key))) {
    return false;
  }

  // Reject dangerous values
  if (params.expression?.includes('eval') || 
      params.path?.includes('..')) {
    return false;
  }

  return true;
}
